from typing import Literal

from pydantic import BaseModel, Field


class PlanListCommand(BaseModel):
    type: Literal["plan_list"] = "plan_list"


class QuoteCommand(BaseModel):
    type: Literal["quote"] = "quote"


class OneShotCommand(BaseModel):
    type: Literal["one_shot"] = "one_shot"
    message: str = Field(min_length=1)


class OneShotMissingMessageCommand(BaseModel):
    type: Literal["one_shot_missing_message"] = "one_shot_missing_message"


Command = PlanListCommand | QuoteCommand | OneShotCommand | OneShotMissingMessageCommand


class RunResult(BaseModel):
    exit_code: int
    output: str
    timed_out: bool = False

import re

from erkbot.models import (
    Command,
    OneShotCommand,
    OneShotMissingMessageCommand,
    PlanListCommand,
    QuoteCommand,
)


def strip_mentions(text: str) -> str:
    return re.sub(r"<@[^>]+>", " ", text).strip()


def parse_erk_command(text: str) -> Command | None:
    message = strip_mentions(text)
    if not message:
        return None

    normalized = " ".join(message.split())
    lowered = normalized.lower()

    if lowered == "plan list":
        return PlanListCommand()
    if lowered == "quote":
        return QuoteCommand()

    one_shot_match = re.match(r"(?i)^one[- ]shot\b", normalized)
    if not one_shot_match:
        return None

    one_shot_message = normalized[one_shot_match.end() :].strip()
    if not one_shot_message:
        return OneShotMissingMessageCommand()
    return OneShotCommand(message=one_shot_message)

import re
from importlib import resources
from importlib.util import find_spec
from pathlib import Path

from erkbot.config import Settings

_QUOTE_RESOURCE_PACKAGE = "erkbot.resources"
_QUOTE_RESOURCE_NAME = "QUOTE.md"
_PR_URL_RE = re.compile(r"^PR:\s+(https://\S+)")
_RUN_URL_RE = re.compile(r"^Run:\s+(https://\S+)")


def extract_slack_message_ts(message_result: object) -> str | None:
    if message_result is None:
        return None
    if isinstance(message_result, dict):
        ts = message_result.get("ts")
        return str(ts) if ts else None

    get_method = getattr(message_result, "get", None)
    if callable(get_method):
        ts = get_method("ts")
        if ts:
            return str(ts)

    data = getattr(message_result, "data", None)
    if isinstance(data, dict):
        ts = data.get("ts")
        return str(ts) if ts else None
    return None


def extract_one_shot_links(output: str) -> tuple[str | None, str | None]:
    pr_url: str | None = None
    run_url: str | None = None
    for line in output.splitlines():
        if pr_url is None:
            pr_match = _PR_URL_RE.match(line.strip())
            if pr_match:
                pr_url = pr_match.group(1)
        if run_url is None:
            run_match = _RUN_URL_RE.match(line.strip())
            if run_match:
                run_url = run_match.group(1)
        if pr_url and run_url:
            break
    return pr_url, run_url


def tail_output_lines(output: str, *, max_lines: int) -> str:
    lines = [line for line in output.splitlines() if line.strip()]
    if len(lines) <= max_lines:
        return "\n".join(lines)
    return "\n".join(lines[-max_lines:])


def chunk_for_slack(text: str, *, max_chars: int) -> list[str]:
    if len(text) <= max_chars:
        return [text]

    chunks: list[str] = []
    current = ""
    for line in text.splitlines():
        candidate = f"{current}\n{line}" if current else line
        if len(candidate) <= max_chars:
            current = candidate
            continue
        if current:
            chunks.append(current)
            current = line
            continue
        remainder = line
        while len(remainder) > max_chars:
            chunks.append(remainder[:max_chars])
            remainder = remainder[max_chars:]
        current = remainder
    if current:
        chunks.append(current)
    return chunks


def build_one_shot_progress_text(*, lines: list[str], running: bool, settings: Settings) -> str:
    state = "⏳ Running `erk one-shot`" if running else "✅ Finished `erk one-shot`."
    if not lines:
        return state
    tail = "\n".join(lines[-settings.one_shot_progress_tail_lines :])
    return f"{state}\n\n```{tail}```"


def load_quote_text() -> str:
    if find_spec(_QUOTE_RESOURCE_PACKAGE) is not None:
        resource_root = resources.files(_QUOTE_RESOURCE_PACKAGE)
        resource_quote_file = resource_root.joinpath(_QUOTE_RESOURCE_NAME)
        if resource_quote_file.is_file():
            quote = resource_quote_file.read_text(encoding="utf-8").strip()
            return quote or "QUOTE.md is empty."

    fallback_quote_file = Path(__file__).parent.joinpath("resources", _QUOTE_RESOURCE_NAME)
    if not fallback_quote_file.is_file():
        return f"{_QUOTE_RESOURCE_NAME} resource was not found."

    quote = fallback_quote_file.read_text(encoding="utf-8").strip()
    return quote or "QUOTE.md is empty."

from collections.abc import AsyncIterator
from dataclasses import dataclass
from typing import Any

from claude_agent_sdk.types import (
    AssistantMessage,
    Message,
    ResultMessage,
    StreamEvent,
    SystemMessage,
)

from erkbot.agent.events import (
    AgentEvent,
    AgentResult,
    TextDelta,
    ToolEnd,
    ToolStart,
    TurnEnd,
    TurnStart,
)


@dataclass(frozen=True)
class _ActiveToolBlock:
    tool_name: str
    tool_use_id: str


async def stream_agent_events(*, messages: AsyncIterator[Message]) -> AsyncIterator[AgentEvent]:
    turn_index = 0
    active_tool: _ActiveToolBlock | None = None
    turn_started = False

    async for message in messages:
        if isinstance(message, StreamEvent):
            event: dict[str, Any] = message.event
            event_type = event.get("type")

            if event_type == "message_start" and not turn_started:
                yield TurnStart(turn_index=turn_index)
                turn_started = True

            elif event_type == "content_block_start":
                content_block = event.get("content_block", {})
                if content_block.get("type") == "tool_use":
                    tool_name = content_block.get("name", "")
                    tool_use_id = content_block.get("id", "")
                    active_tool = _ActiveToolBlock(tool_name=tool_name, tool_use_id=tool_use_id)
                    yield ToolStart(tool_name=tool_name, tool_use_id=tool_use_id)

            elif event_type == "content_block_delta":
                delta = event.get("delta", {})
                if delta.get("type") == "text_delta":
                    text = delta.get("text", "")
                    if text:
                        yield TextDelta(text=text)

            elif event_type == "content_block_stop":
                if active_tool is not None:
                    yield ToolEnd(
                        tool_name=active_tool.tool_name,
                        tool_use_id=active_tool.tool_use_id,
                    )
                    active_tool = None

        elif isinstance(message, AssistantMessage):
            yield TurnEnd(turn_index=turn_index)
            turn_index += 1
            turn_started = False

        elif isinstance(message, ResultMessage):
            usage = message.usage or {}
            yield AgentResult(
                session_id=message.session_id,
                num_turns=message.num_turns,
                input_tokens=usage.get("input_tokens", 0),
                output_tokens=usage.get("output_tokens", 0),
            )

        elif isinstance(message, SystemMessage):
            continue

